localparam integer NUM_LFSR = num_lfsr(DATA_WIDTH);
function integer num_lfsr;
  input integer data_width;
  integer result;
  begin
    result = 1;
    while ((data_width + result - 1) / result > 36) result = result * 2;
    num_lfsr = result;
  end
endfunction

localparam MAX_LFSR_WIDTH = 36;
function integer num_lfsr;
  input integer data_width;
  begin
    while (data_width > MAX_LFSR_WIDTH) num_lfsr = num_lfsr * 2;
  end
endfunction
localparam integer NUM = num_lfsr(64);
